# 3) Show larger chunks around each occurrence for manual patching
for ln in $(grep -n "cttz" "$file" | cut -d: -f1); do
  start=$((ln-40)); [ $start -lt 1 ] && start=1; end=$((ln+80))
  echo "----- Context around line $ln -----"
  nl -ba "$file" | sed -n "${start},${end}p" | sed 's/\t/    /g'
done
# 4) Apply a conservative patch: Do not flip isZeroUndef from false->true for cttz/ctlz if the call has noundef on return.
# We'll inject a guard near where InstCombine canonicalizes to isZeroUndef=true.
