# We'll try to find a common code sequence that sets IsZeroUndef to true or recreates the call with true.
# Heuristic insertion: right after we detect Intrinsic::cttz or Intrinsic::ctlz in a switch, add an early guard.

def inject_guard(block, which):
    # which is 'cttz' or 'ctlz'
    guard = f'''
    // Guard: Avoid flipping {which}(x, false) -> {which}(x, true) if return has noundef,
    // unless we can prove x != 0. This preserves definedness when x==0.
    if (auto *II_local = dyn_cast<IntrinsicInst>(CI)) {{
      if (II_local->getIntrinsicID() == Intrinsic::{which}) {{
        if (auto *Z = dyn_cast<ConstantInt>(CI->getArgOperand(1))) {{
          if (!Z->isOne()) {{
            // isZeroUndef == false currently
            // If return is noundef and operand may be zero, do not transform to isZeroUndef=true.
            bool RetNoUndef = CI->hasRetAttr(Attribute::NoUndef) || CI->hasAttribute(Attribute::NoUndef);
            if (RetNoUndef) {{
              // Try a best-effort nonzero check; if not available here, conservatively bail.
              bool KnownNonZero = false;
              if (auto *Xv = CI->getArgOperand(0)) {{
                const DataLayout &DL = CI->getModule()->getDataLayout();
                KnownNonZero = IC.isKnownNonZero(Xv, DL, 0, CI);
              }}
              if (!KnownNonZero)
                break;
            }}
          }}
        }}
      }}
    }}
'''
    # Insert guard before any potential rewrite. Place it near the beginning of the case block.
    # Try to put after opening brace of case block.
    return block + guard

changed = s
for intr in ('cttz','ctlz'):
    # Find the case block for the intrinsic
    pat = re.compile(rf'(case\s+Intrinsic::{intr}\s*:[\s\S]*?)(\n\s*break\s*;\s*\n)', re.M)
    def repl(m):
        blk = m.group(1)
        end = m.group(2)
        if 'Avoid flipping' in blk:
            return m.group(0)
        return inject_guard(blk, intr) + end
