THOUGHT: InstCombine was canonicalizing cttz(x, false) used as a shift amount to cttz(x, true). With a noundef result, this is UB for x==0. My earlier fix dropped noundef in-place but seems to have introduced a hang in InstCombine tests. I will instead replace the call with a freshly created intrinsic call with is_zero_poison=true, and selectively drop the noundef return attribute if the operand may be zero. Replacing the instruction rather than mutating operands/attributes in-place should avoid any combine loop. I’ll patch foldCttzCtlz accordingly, rebuild, sanity-check the repro, ensure the specific test file no longer hangs, and submit the patch.

```bash
python3 - << 'PY'
import re, subprocess, sys, pathlib, textwrap

p = pathlib.Path("llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp")
s = p.read_text(encoding="utf-8")
orig = s

# Remove any prior injected guard snippet (from earlier attempts), if present.
s = s.replace(" && !II.hasRetAttr(Attribute::NoUndef)", "")
if "// If we canonicalize to is_zero_poison=true" in s:
    # Remove the previously injected guard block before the return.
    pattern_guard = re.compile(r"\n\s*// If we canonicalize to is_zero_poison=true[\s\S]*?}\n", re.M)
    s, n = pattern_guard.subn("\n", s)

anchor = "// If ctlz/cttz is only used as a shift amount, set is_zero_poison to true."
idx = s.find(anchor)
if idx == -1:
    print("Anchor not found; aborting.", file=sys.stderr)
    sys.exit(1)

# Find the exact return line we want to replace.
ret_pat = r"return\s+IC\.replaceOperand\(II,\s*1,\s*IC\.Builder\.getTrue\(\)\);\s*"
m = re.search(ret_pat, s[idx:])
if not m:
    print("Return line for is_zero_poison transform not found; aborting.", file=sys.stderr)
    sys.exit(1)

# Build replacement block: create a new call with arg1=true, drop NoUndef if Op0 may be zero,
# then replace the old instruction with the new call.
new_block = textwrap.dedent(r"""
    {
      // Create a new call with is_zero_poison=true.
      auto *NewCall = IC.Builder.CreateBinaryIntrinsic(II.getIntrinsicID(), Op0, IC.Builder.getTrue());
      if (auto *NewCI = dyn_cast<CallInst>(NewCall)) {
        // Preserve attributes from the old call.
        NewCI->setAttributes(II.getAttributes());
        // If return has noundef, but operand may be zero, drop noundef to avoid UB for x==0.
        if (NewCI->hasRetAttr(Attribute::NoUndef)) {
          auto SQ = IC.getSimplifyQuery().getWithInstruction(&II);
          if (!isKnownNonZero(Op0, SQ))
            NewCI->removeRetAttr(Attribute::NoUndef);
        }
      }
      return IC.replaceInstUsesWith(II, NewCall);
    }
""").strip("\n")

start = idx + m.start()
end = idx + m.end()
s = s[:start] + new_block + s[end:]

if s == orig:
    print("No changes made; file may already be patched.", file=sys.stderr)
else:
    p.write_text(s, encoding="utf-8")
    print("Patched", p)

# Rebuild LLVM
subprocess.check_call(["ninja","-C","/llvm-autofix/build/llvm-build/112068"])

