print(out)
# Check that we set arg1 to true and there is no 'noundef' on the cttz call.
assert "cttz.i32(i32 %y, i1 true)" in out
assert "noundef" not in out.split("cttz")[0] or "noundef" not in out, "noundef should be dropped on the cttz call"

